from dataclasses import dataclass, field
from typing import Optional

@dataclass
class ApprovedToolEntry:
    vendor_name: str
    endpoint_domain: str
    data_classifications_permitted: list[str]   # e.g. ["internal", "public"]
    requires_approval_for: list[str]            # e.g. ["pii", "confidential"]
    dpa_signed: bool
    data_residency_confirmed: bool
    approved_by: str
    approval_date: str
    review_due: str

    def can_process(self, data_classification: str) -> bool:
        if data_classification in self.data_classifications_permitted:
            return True
        if data_classification in self.requires_approval_for:
            return None  # caller should check for explicit approval
        return False

    def is_compliant(self) -> bool:
        return self.dpa_signed and self.data_residency_confirmed

@dataclass
class ToolRegistry:
    entries: list[ApprovedToolEntry] = field(default_factory=list)

    def approved_domains(self) -> list[str]:
        return [e.endpoint_domain for e in self.entries if e.is_compliant()]

    def lookup(self, domain: str) -> Optional[ApprovedToolEntry]:
        return next((e for e in self.entries if e.endpoint_domain == domain), None)

import re
from dataclasses import dataclass
from typing import Optional
from enum import Enum

class GovDecision(str, Enum):
    PERMIT = "permit"
    FLAG_AND_PERMIT = "flag_and_permit"   # conditional: log and allow
    BLOCK = "block"

# Patterns that trigger immediate block
BLOCK_PATTERNS = [
    r"\b(password|secret|api[_\-]?key|bearer token)\s*[:=]\s*\S{8,}",
    r"(generate|write|create).{0,30}(malware|exploit|rootkit|phishing)",
    r"\b(SSN|social security|NI number)\b.{0,20}\d{6,9}",
]

# Terms requiring elevated role for the request to continue
CONDITIONAL_TERMS = [
    "employee performance", "salary band", "termination",
    "customer pii", "credit score", "hire/fire",
]

@dataclass
class GovernanceResult:
    decision: GovDecision
    matched_rule: Optional[str]
    log_required: bool
    user_message: Optional[str]

def evaluate_prompt(prompt: str, user_roles: list[str]) -> GovernanceResult:
    lp = prompt.lower()

    for pattern in BLOCK_PATTERNS:
        if re.search(pattern, prompt, re.IGNORECASE):
            return GovernanceResult(
                decision=GovDecision.BLOCK,
                matched_rule=f"prohibited pattern: {pattern[:40]}",
                log_required=True,
                user_message="This prompt contains information that cannot be submitted to a GenAI tool under the AUP. Please remove sensitive credentials or prohibited content.",
            )

    for term in CONDITIONAL_TERMS:
        if term in lp:
            if not any(r in user_roles for r in ["hr_approved", "data_owner"]):
                return GovernanceResult(
                    decision=GovDecision.BLOCK,
                    matched_rule=f"conditional term without role: {term}",
                    log_required=True,
                    user_message=f"Access to GenAI features involving '{term}' requires HR approval. Contact your manager.",
                )
            return GovernanceResult(
                decision=GovDecision.FLAG_AND_PERMIT,
                matched_rule=f"conditional term (role confirmed): {term}",
                log_required=True,
                user_message=None,
            )

    return GovernanceResult(
        decision=GovDecision.PERMIT,
        matched_rule=None,
        log_required=False,
        user_message=None,
    )

from dataclasses import dataclass, field
from datetime import datetime

KNOWN_AI_CONSUMER_DOMAINS = [
    "chat.openai.com", "claude.ai", "bard.google.com",
    "gemini.google.com", "perplexity.ai", "huggingface.co",
    "poe.com", "character.ai",
]

@dataclass
class ProxyEvent:
    employee_id: str
    timestamp: datetime
    destination: str
    bytes_uploaded: int
    bytes_downloaded: int
    approved: bool   # domain in approved registry

@dataclass
class ShadowAIDetectionResult:
    employee_id: str
    period_days: int
    flagged_events: list[ProxyEvent] = field(default_factory=list)
    total_bytes_to_unapproved: int = 0

    def is_significant(self) -> bool:
        # More than 5 events or > 50 KB uploaded to unapproved AI domains
        return len(self.flagged_events) > 5 or self.total_bytes_to_unapproved > 51_200

    def top_destinations(self) -> dict[str, int]:
        counts: dict[str, int] = {}
        for ev in self.flagged_events:
            counts[ev.destination] = counts.get(ev.destination, 0) + 1
        return dict(sorted(counts.items(), key=lambda x: x[1], reverse=True))

    def summary(self) -> str:
        return (
            f"Employee {self.employee_id} | "
            f"{len(self.flagged_events)} unapproved-AI events over {self.period_days} days | "
            f"{self.total_bytes_to_unapproved / 1024:.1f} KB uploaded | "
            f"Significant: {self.is_significant()}"
        )

def analyse_proxy_log(
    events: list[ProxyEvent],
    approved_domains: set[str],
    period_days: int = 30,
) -> list[ShadowAIDetectionResult]:
    by_employee: dict[str, ShadowAIDetectionResult] = {}

    for ev in events:
        is_ai = any(d in ev.destination for d in KNOWN_AI_CONSUMER_DOMAINS)
        is_approved = any(d in ev.destination for d in approved_domains)
        if is_ai and not is_approved and ev.bytes_uploaded > 512:
            r = by_employee.setdefault(ev.employee_id, ShadowAIDetectionResult(ev.employee_id, period_days))
            r.flagged_events.append(ev)
            r.total_bytes_to_unapproved += ev.bytes_uploaded

    return [r for r in by_employee.values() if r.is_significant()]

from dataclasses import dataclass
from enum import Enum
from typing import Optional
from datetime import datetime

class ViolationSeverity(Enum):
    LOW = "low"           # Inadvertent; no material risk
    MEDIUM = "medium"     # Conditional use without approval; limited exposure
    HIGH = "high"         # Prohibited act; material risk or actual harm
    CRITICAL = "critical" # Intentional; repeated; significant damage or disclosure

@dataclass
class TriagedViolation:
    incident_id: str
    employee_id: str
    detected_at: datetime
    detection_source: str     # "proxy", "governance_layer", "user_report", "audit"
    description: str
    severity: ViolationSeverity
    data_exfiltrated: bool
    data_classification: str  # "public", "internal", "confidential", "special_category"
    tool_used: str
    tool_approved: bool

    def requires_access_suspension(self) -> bool:
        return (
            self.severity in (ViolationSeverity.HIGH, ViolationSeverity.CRITICAL) or
            self.data_exfiltrated
        )

    def requires_dpo_notification(self) -> bool:
        return (
            self.data_exfiltrated and
            self.data_classification in ("confidential", "special_category", "pii")
        )

    def requires_regulatory_disclosure(self) -> bool:
        # Simplified: regulated sectors may have lower thresholds
        return self.requires_dpo_notification() and self.severity == ViolationSeverity.CRITICAL

    def response_sla_hours(self) -> int:
        slas = {
            ViolationSeverity.LOW: 72,
            ViolationSeverity.MEDIUM: 24,
            ViolationSeverity.HIGH: 4,
            ViolationSeverity.CRITICAL: 1,
        }
        return slas[self.severity]

    def standard_response(self) -> str:
        responses = {
            ViolationSeverity.LOW:      "Document; remind employee; assign AUP refresher module.",
            ViolationSeverity.MEDIUM:   "Manager notification; written warning; mandatory re-training.",
            ViolationSeverity.HIGH:     "Suspend AI tool access; HR investigation; legal review if data involved.",
            ViolationSeverity.CRITICAL: "Immediate suspension; HR + Legal + DPO; consider law enforcement referral.",
        }
        return responses[self.severity]
